"""Configuration file management"""

import configparser
import logging
import os
from pathlib import Path

log = logging.getLogger(__name__)

DEFAULT_CONFIG_PATH = "/etc/att_gateway/att_gateway.conf"


class Config:
    """Configuration manager for att-gateway-check.

    Reads INI-format configuration file.
    """

    def __init__(self, config_path=None):
        """Initialize configuration manager.

        Args:
            config_path: Path to config file (defaults to /etc/att_gateway/att_gateway.conf)
        """
        self.config_path = config_path or DEFAULT_CONFIG_PATH
        # Only use '=' as delimiter to avoid issues with colons in MAC addresses
        self.parser = configparser.ConfigParser(delimiters=('=',))
        self.loaded = False

    def load(self):
        """Load configuration from file.

        Returns:
            True if loaded successfully

        Raises:
            FileNotFoundError: If config file doesn't exist
        """
        if not os.path.exists(self.config_path):
            raise FileNotFoundError(
                f"Configuration file not found: {self.config_path}\n"
                f"Please create it from the template:\n"
                f"  sudo cp /etc/att_gateway/att_gateway.conf.template {self.config_path}\n"
                f"  sudo nano {self.config_path}"
            )

        try:
            self.parser.read(self.config_path)
            self.loaded = True
            log.info(f"Loaded configuration from {self.config_path}")
            return True
        except Exception as e:
            log.error(f"Failed to parse config file: {e}")
            raise

    def get(self, section, key, fallback=None):
        """Get a configuration value.

        Args:
            section: Config section name
            key: Config key name
            fallback: Default value if not found

        Returns:
            Configuration value or fallback
        """
        if not self.loaded:
            raise RuntimeError("Config not loaded - call load() first")

        return self.parser.get(section, key, fallback=fallback)

    def getboolean(self, section, key, fallback=False):
        """Get a boolean configuration value.

        Args:
            section: Config section name
            key: Config key name
            fallback: Default value if not found

        Returns:
            Boolean configuration value or fallback
        """
        if not self.loaded:
            raise RuntimeError("Config not loaded - call load() first")

        return self.parser.getboolean(section, key, fallback=fallback)

    def getint(self, section, key, fallback=0):
        """Get an integer configuration value.

        Args:
            section: Config section name
            key: Config key name
            fallback: Default value if not found

        Returns:
            Integer configuration value or fallback
        """
        if not self.loaded:
            raise RuntimeError("Config not loaded - call load() first")

        return self.parser.getint(section, key, fallback=fallback)

    def has_section(self, section):
        """Check if a section exists.

        Args:
            section: Section name

        Returns:
            True if section exists
        """
        if not self.loaded:
            raise RuntimeError("Config not loaded - call load() first")

        return self.parser.has_section(section)

    def items(self, section):
        """Get all items in a section.

        Args:
            section: Section name

        Returns:
            List of (key, value) tuples
        """
        if not self.loaded:
            raise RuntimeError("Config not loaded - call load() first")

        if not self.parser.has_section(section):
            return []

        return self.parser.items(section)

    # Convenience methods for common settings

    def get_gateway_host(self):
        """Get gateway hostname/IP."""
        return self.get('gateway', 'host', fallback='192.168.1.254')

    def get_gateway_password(self):
        """Get gateway password."""
        password = self.get('gateway', 'password', fallback=None)
        if not password or password == '<set-your-password>':
            raise ValueError(
                "Gateway password not configured!\n"
                f"Please edit {self.config_path} and set the password."
            )
        return password

    def is_check_enabled(self):
        """Check if check mode is enabled."""
        return self.getboolean('check', 'enabled', fallback=True)

    def is_auto_fix_enabled(self):
        """Check if auto-fix is enabled."""
        return self.getboolean('check', 'auto_fix', fallback=True)

    def get_expected_public_subnet(self):
        """Get expected public subnet configuration.

        Returns:
            Dictionary with expected public subnet settings
        """
        if not self.has_section('check:public_subnet'):
            return None

        if not self.getboolean('check:public_subnet', 'enabled', fallback=False):
            return None

        return {
            'pubsub': self.get('check:public_subnet', 'pubsub', fallback='on'),
            'ain': self.get('check:public_subnet', 'ain', fallback='on'),
            'pubipaddr': self.get('check:public_subnet', 'pubipaddr', fallback=''),
            'pubmask': self.get('check:public_subnet', 'pubmask', fallback=''),
            'pubdhcpstart': self.get('check:public_subnet', 'pubdhcpstart', fallback=''),
            'pubdhcpend': self.get('check:public_subnet', 'pubdhcpend', fallback=''),
            'primpool': self.get('check:public_subnet', 'primpool', fallback='private'),
        }

    def get_expected_ip_allocations(self):
        """Get expected IP allocation mappings.

        Returns:
            Dictionary mapping MAC addresses to expected IPs
        """
        if not self.has_section('check:ip_allocations'):
            return {}

        if not self.getboolean('check:ip_allocations', 'enabled', fallback=False):
            return {}

        allocations = {}
        for mac, ip in self.items('check:ip_allocations'):
            if mac != 'enabled':  # Skip the enabled flag
                allocations[mac.lower()] = ip

        return allocations

    def get_backup_directory(self):
        """Get backup directory path."""
        return self.get('backup', 'directory', fallback='/var/lib/att_gateway/backups')

    def get_backup_retention_count(self):
        """Get backup retention count."""
        return self.getint('backup', 'retention_count', fallback=30)

    def get_backup_retention_days(self):
        """Get backup retention days."""
        return self.getint('backup', 'retention_days', fallback=90)

    def get_log_level(self):
        """Get logging level."""
        level_str = self.get('logging', 'level', fallback='INFO').upper()
        return getattr(logging, level_str, logging.INFO)
